impl Default for ProgramState {
    fn default() -> Self {
        unsafe { std::mem::MaybeUninit::zeroed().assume_init() }
    }
}

impl ProgramState {
    pub fn odd_record(&self) -> bool { format!("{}", self.sub).trim() == "1" }
}

/// OPEN INPUT OPTIONAL
fn optional_open_input(state: &mut ProgramState) {
    let path = std::env::var("OPTIONAL").unwrap_or("optional.dat".to_string());
    match CobolFile::open_input(&path) {
        Ok(handle) => { state._fh_optional = handle; state._fs_optional = FileStatus::Success; }
        Err(_) => { state._fs_optional = FileStatus::Error("35".to_string()); }
    }
    { let _s = format!("{}", state._fs_optional); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
}

