/// READ OPTIONAL
fn optional_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_optional.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(80);
            state._fs_optional = FileStatus::Success;
    { let _s = format!("{}", state._fs_optional); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
        Err(FileStatus::AtEnd) => {
            state._fs_optional = FileStatus::AtEnd;
    { let _s = format!("{}", state._fs_optional); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
        Err(e) => {
            state._fs_optional = e.clone();
    { let _s = format!("{}", state._fs_optional); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
    }
    Ok(())
}

