/// READ TSTFILE
fn tstfile_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_tstfile.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(172);
            if _len > 0 { let _end = _len.min(0+8); state.ts_cust_num = String::from_utf8_lossy(&_bytes[0.._end]).to_string().cobol_into(); }
            if _len > 8 { let _end = _len.min(8+1); state.ts_status = String::from_utf8_lossy(&_bytes[8.._end]).to_string().cobol_into(); }
            if _len > 9 { let _end = _len.min(9+25); state.ts_company = String::from_utf8_lossy(&_bytes[9.._end]).to_string().cobol_into(); }
            if _len > 34 { let _end = _len.min(34+25); state.ts_address_1 = String::from_utf8_lossy(&_bytes[34.._end]).to_string().cobol_into(); }
            if _len > 59 { let _end = _len.min(59+25); state.ts_address_2 = String::from_utf8_lossy(&_bytes[59.._end]).to_string().cobol_into(); }
            if _len > 84 { let _end = _len.min(84+25); state.ts_address_3 = String::from_utf8_lossy(&_bytes[84.._end]).to_string().cobol_into(); }
            if _len > 109 { let _end = _len.min(109+10); let _s = String::from_utf8_lossy(&_bytes[109.._end]).trim().to_string(); state.ts_telephone = _s.cobol_into(); }
            if _len > 119 { let _end = _len.min(119+25); state.ts_dp_mgr = String::from_utf8_lossy(&_bytes[119.._end]).to_string().cobol_into(); }
            if _len > 144 { let _end = _len.min(144+8); state.ts_machine = String::from_utf8_lossy(&_bytes[144.._end]).to_string().cobol_into(); }
            if _len > 152 { let _end = _len.min(152+4); state.ts_memory = String::from_utf8_lossy(&_bytes[152.._end]).to_string().cobol_into(); }
            if _len > 156 { let _end = _len.min(156+8); state.ts_disk = String::from_utf8_lossy(&_bytes[156.._end]).to_string().cobol_into(); }
            if _len > 164 { let _end = _len.min(164+8); state.ts_tape = String::from_utf8_lossy(&_bytes[164.._end]).to_string().cobol_into(); }
            state._fs_tstfile = FileStatus::Success;
    { let _s = format!("{}", state._fs_tstfile); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
        Err(FileStatus::AtEnd) => {
            state._fs_tstfile = FileStatus::AtEnd;
    { let _s = format!("{}", state._fs_tstfile); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
        Err(e) => {
            state._fs_tstfile = e.clone();
    { let _s = format!("{}", state._fs_tstfile); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
    }
    Ok(())
}

/// WRITE to TSTFILE
fn tstfile_write(state: &mut ProgramState) {
    let mut _buf = vec![b' '; 172];
    { let _src = state.ts_cust_num.as_bytes(); let _end = (0+8).min(_buf.len()); let _cl = _src.len().min(_end-0); _buf[0..0+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.ts_status.as_bytes(); let _end = (8+1).min(_buf.len()); let _cl = _src.len().min(_end-8); _buf[8..8+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.ts_company.as_bytes(); let _end = (9+25).min(_buf.len()); let _cl = _src.len().min(_end-9); _buf[9..9+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.ts_address_1.as_bytes(); let _end = (34+25).min(_buf.len()); let _cl = _src.len().min(_end-34); _buf[34..34+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.ts_address_2.as_bytes(); let _end = (59+25).min(_buf.len()); let _cl = _src.len().min(_end-59); _buf[59..59+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.ts_address_3.as_bytes(); let _end = (84+25).min(_buf.len()); let _cl = _src.len().min(_end-84); _buf[84..84+_cl].copy_from_slice(&_src[.._cl]); }
    { let _s = format!("{:>width$}", state.ts_telephone, width = 10); let _b = _s.as_bytes(); let _cl = _b.len().min(10); _buf[109..109+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    { let _src = state.ts_dp_mgr.as_bytes(); let _end = (119+25).min(_buf.len()); let _cl = _src.len().min(_end-119); _buf[119..119+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.ts_machine.as_bytes(); let _end = (144+8).min(_buf.len()); let _cl = _src.len().min(_end-144); _buf[144..144+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.ts_memory.as_bytes(); let _end = (152+4).min(_buf.len()); let _cl = _src.len().min(_end-152); _buf[152..152+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.ts_disk.as_bytes(); let _end = (156+8).min(_buf.len()); let _cl = _src.len().min(_end-156); _buf[156..156+_cl].copy_from_slice(&_src[.._cl]); }
    { let _src = state.ts_tape.as_bytes(); let _end = (164+8).min(_buf.len()); let _cl = _src.len().min(_end-164); _buf[164..164+_cl].copy_from_slice(&_src[.._cl]); }
    match state._fh_tstfile.write_record(&_buf) {
        Ok(()) => state._fs_tstfile = FileStatus::Success,
        Err(e) => state._fs_tstfile = e,
    }
}

/// CLOSE TSTFILE
fn tstfile_close(state: &mut ProgramState) {
    match state._fh_tstfile.close() {
        Ok(()) => state._fs_tstfile = FileStatus::Success,
        Err(e) => state._fs_tstfile = e,
    }
    { let _s = format!("{}", state._fs_tstfile); let _b = _s.as_bytes(); unsafe { let p = &mut state.cust_stat as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
}

